#version 300 es
precision highp float;
uniform float u_time;
uniform vec2 u_resolution;
uniform vec2 u_touch;
in vec2 v_uv;
out vec4 fragColor;
void main() {
  vec2 uv = v_uv;
  float t = u_time * 0.3;
  vec3 col = vec3(
    sin(uv.x * 3.0 + t) * 0.5 + 0.5,
    cos(uv.y * 2.0 + t * 1.2) * 0.5 + 0.5,
    sin(uv.x + uv.y + t * 0.8) * 0.5 + 0.5
  );
  fragColor = vec4(col, 1.0);
}

